# ── Helpers: CLIP model ───────────────────────────────────────────────────────
@st.cache_resource(show_spinner="Loading AI model (first run only)…")
def load_clip():
    import torch
    import open_clip
    device = "mps" if hasattr(__import__("torch").backends, "mps") and \
              __import__("torch").backends.mps.is_available() else "cpu"
    model, _, preprocess = open_clip.create_model_and_transforms(
        MODEL_NAME, pretrained=PRETRAINED)
    model.eval().to(device)
    tokenizer = open_clip.get_tokenizer(MODEL_NAME)
    return model, preprocess, tokenizer, device


def embed_text(query: str):
    import torch
    model, _, tokenizer, device = load_clip()
    # CLIP was trained on full photo captions, not bare words — wrapping the
    # query in a caption-like template gives noticeably better matches for
    # short/specific searches like "pearl" or "sapphire".
    prompted = f"a photo of {query.strip()} jewelry"
    with torch.no_grad():
        tokens = tokenizer([prompted]).to(device)
        feat = model.encode_text(tokens)
        feat = feat / feat.norm(dim=-1, keepdim=True)
    return feat.cpu().numpy().astype("float32")[0]


def isolate_jewelry(pil_img: Image.Image) -> Image.Image:
    """
    Crop tight to the jewelry and neutralize the backdrop, using a simple
    corner/border-color heuristic — no ML model, no extra dependencies, no
    network call. (We tried rembg/numba for true segmentation first; it
    proved too fragile in this hosting environment — blank app, native
    crash, and a silent hang across three separate deploys. This approach
    uses only PIL/numpy, which are already solid here, so it structurally
    cannot hang or crash the way that did.)

    Why bother at all: raw CLIP embeddings of full photos capture
    photography style — white seamless paper, studio lighting, framing —
    as strongly as the object itself. That makes a studio product shot
    match other studio product shots first, regardless of whether it's
    actually the same piece. Cropping out the dead background space and
    flattening what's left toward a neutral color reduces how much "white
    studio backdrop" dominates the embedding versus the jewelry itself.
    """
    try:
        arr = np.asarray(pil_img.convert("RGB")).astype(np.int16)
        h, w = arr.shape[:2]

        # Estimate the background color from a thin strip around all four
        # edges (median, so a single stray reflection/shadow in one corner
        # doesn't skew it).
        border = max(4, min(h, w) // 50)
        border_px = np.concatenate([
            arr[:border, :, :].reshape(-1, 3),
            arr[-border:, :, :].reshape(-1, 3),
            arr[:, :border, :].reshape(-1, 3),
            arr[:, -border:, :].reshape(-1, 3),
        ])
        bg_color = np.median(border_px, axis=0)

        dist = np.sqrt(((arr - bg_color) ** 2).sum(axis=-1))
        threshold = 28  # empirically reasonable for clean studio backgrounds
        mask = dist > threshold

        ys, xs = np.where(mask)
        if len(xs) == 0 or len(ys) == 0:
            # Nothing detected as different from the background — leave as-is
            # rather than risk cropping to an empty/garbage region.
            return pil_img

        x0, x1 = xs.min(), xs.max()
        y0, y1 = ys.min(), ys.max()
        pad_x = int((x1 - x0) * ISOLATE_PADDING) + 1
        pad_y = int((y1 - y0) * ISOLATE_PADDING) + 1
        x0 = max(0, x0 - pad_x); x1 = min(w, x1 + pad_x)
        y0 = max(0, y0 - pad_y); y1 = min(h, y1 + pad_y)

        cropped = arr[y0:y1, x0:x1].copy()
        crop_mask = mask[y0:y1, x0:x1]
        # Flatten background-ish pixels toward the neutral backdrop color so
        # residual white/off-white framing doesn't dominate the embedding.
        cropped[~crop_mask] = ISOLATE_BG_COLOR
        return Image.fromarray(np.clip(cropped, 0, 255).astype("uint8"), "RGB")
    except Exception:
        return pil_img


def embed_image(pil_img: Image.Image):
    import torch
    model, preprocess, _, device = load_clip()
    isolated = isolate_jewelry(pil_img)
    with torch.no_grad():
        tensor = preprocess(isolated).unsqueeze(0).to(device)
        feat = model.encode_image(tensor)
        feat = feat / feat.norm(dim=-1, keepdim=True)
    return feat.cpu().numpy().astype("float32")[0]


# ── Helpers: Google Drive ─────────────────────────────────────────────────────
def _execute_with_retry(request, max_retries: int = 4, base_delay: float = 1.0):
    """
    Run a Google API request's .execute(), retrying transient network
    failures (dropped SSL connections, read timeouts, 5xx/429 responses)
    with exponential backoff + jitter.

    Streamlit Cloud's outbound connections to Google occasionally get reset
    mid-request (raw ssl.SSLError / socket errors bubbling up through
    httplib2). Without retrying, a single blip crashes the whole app since
    these calls happen at page-load time, not just on user actions.
    """
    from googleapiclient.errors import HttpError

    last_err = None
    for attempt in range(max_retries):
        try:
            return request.execute()
        except HttpError as e:
            status = getattr(e.resp, "status", None)
            if status not in (429, 500, 502, 503, 504):
                raise
            last_err = e
        except (ssl.SSLError, ConnectionError, TimeoutError, OSError) as e:
            last_err = e

        if attempt < max_retries - 1:
            time.sleep(base_delay * (2 ** attempt) + random.uniform(0, 0.5))

    raise last_err


@st.cache_resource(show_spinner="Connecting to Google Drive…")
def get_drive_service():
    """
    Authenticate with Google Drive.
    Credentials come from st.secrets["google_service_account"] (JSON key)
    when deployed on Streamlit Cloud, or from local credentials.json / token.json
    when running locally (same OAuth flow as the other scripts).
    """
    try:
        # ── Streamlit Cloud: service-account JSON in secrets ──
        from google.oauth2 import service_account
        from googleapiclient.discovery import build
        info = dict(st.secrets["google_service_account"])
        creds = service_account.Credentials.from_service_account_info(
            info, scopes=["https://www.googleapis.com/auth/drive"])
        return build("drive", "v3", credentials=creds)
    except (KeyError, FileNotFoundError):
        pass

    # ── Local: reuse OAuth token from the other scripts ──
    from google.auth.transport.requests import Request
    from google.oauth2.credentials import Credentials
    from google_auth_oauthlib.flow import InstalledAppFlow
    from googleapiclient.discovery import build

    SCOPES = ["https://www.googleapis.com/auth/drive"]
    TOKEN   = "token.json"
    CREDS   = "credentials.json"

    creds = None
    if os.path.exists(TOKEN):
        creds = Credentials.from_authorized_user_file(TOKEN, SCOPES)
    if not creds or not creds.valid:
        if creds and creds.expired and creds.refresh_token:
            creds.refresh(Request())
        else:
            flow = InstalledAppFlow.from_client_secrets_file(CREDS, SCOPES)
            creds = flow.run_local_server(port=0)
        with open(TOKEN, "w") as f:
            f.write(creds.to_json())
    return build("drive", "v3", credentials=creds)


def list_drive_images(service, folder_id: str) -> list[dict]:
    """Return all image files under a Drive folder (recursive)."""
    results, page_token, seen = [], None, set()

    def _recurse(fid):
        nonlocal page_token
        q = f"'{fid}' in parents and trashed = false"
        pt = None
        while True:
            resp = _execute_with_retry(service.files().list(
                q=q,
                fields="nextPageToken, files(id, name, mimeType, thumbnailLink, webContentLink)",
                pageSize=1000, pageToken=pt,
            ))
            for item in resp.get("files", []):
                if item["mimeType"] == "application/vnd.google-apps.folder":
                    if item["id"] not in seen:
                        seen.add(item["id"])
                        _recurse(item["id"])
                elif item["mimeType"].startswith("image/"):
                    results.append(item)
            pt = resp.get("nextPageToken")
            if not pt:
                break

    _recurse(folder_id)
    return results


def fetch_image_bytes(service, file_id: str) -> bytes:
    from googleapiclient.http import MediaIoBaseDownload
    request = service.files().get_media(fileId=file_id)
    buf = io.BytesIO()
    dl = MediaIoBaseDownload(buf, request)
    done = False
    while not done:
        _, done = dl.next_chunk()
    return buf.getvalue()


# ── Index management ──────────────────────────────────────────────────────────
def _find_file_by_name(service, folder_id: str, name: str):
    """Return the Drive file ID of a file with the given name in this folder, if any."""
    resp = _execute_with_retry(service.files().list(
        q=f"'{folder_id}' in parents and name='{name}' and trashed=false",
        fields="files(id, name)",
    ))
    files = resp.get("files", [])
    return files[0]["id"] if files else None


def find_index_file(service, folder_id: str):
    """Return the Drive file ID of the index .npz if it exists."""
    return _find_file_by_name(service, folder_id, INDEX_FILENAME)


def load_index(service, folder_id: str):
    """Load the pre-built CLIP index from Drive into memory."""
    idx_id = find_index_file(service, folder_id)
    if not idx_id:
        return None
    raw = fetch_image_bytes(service, idx_id)
    data = np.load(io.BytesIO(raw), allow_pickle=True)
    return {
        "embeddings": data["embeddings"],
        "ids":        [str(x) for x in data["ids"]],
        "names":      [str(x) for x in data["names"]],
    }


def save_index(service, folder_id: str, index: dict):
    """Save / overwrite the CLIP index .npz back to Drive."""
    from googleapiclient.http import MediaIoBaseUpload
    buf = io.BytesIO()
    np.savez(buf,
             embeddings=index["embeddings"],
             ids=np.array(index["ids"]),
             names=np.array(index["names"]))
    buf.seek(0)
    media = MediaIoBaseUpload(buf, mimetype="application/octet-stream")

    existing_id = find_index_file(service, folder_id)
    if existing_id:
        _execute_with_retry(service.files().update(fileId=existing_id, media_body=media))
    else:
        meta = {"name": INDEX_FILENAME, "parents": [folder_id]}
        _execute_with_retry(service.files().create(body=meta, media_body=media))


def _merge_index(existing_embs, existing_ids, existing_names,
                  new_embeddings, new_ids, new_names) -> dict:
    """Stack new photo embeddings onto whatever was already indexed."""
    new_emb_arr = np.stack(new_embeddings)
    if existing_embs is not None and len(existing_embs) > 0:
        merged_embs  = np.concatenate([existing_embs, new_emb_arr], axis=0)
        merged_ids   = list(existing_ids)   + list(new_ids)
        merged_names = list(existing_names) + list(new_names)
    else:
        merged_embs  = new_emb_arr
        merged_ids   = list(new_ids)
        merged_names = list(new_names)
    return {"embeddings": merged_embs, "ids": merged_ids, "names": merged_names}


def build_index(service, folder_id: str, progress_bar, existing_index=None):
    """
    Build or incrementally update the CLIP index.

    If existing_index is provided, only new photos (file IDs not already in
    the index) are processed. This makes daily updates take seconds rather
    than minutes -- only the genuinely new photos are touched.

    If existing_index is None, all photos are processed from scratch.
    """
    import torch
    model, preprocess, _, device = load_clip()

    all_files = list_drive_images(service, folder_id)

    # ── Incremental: skip anything already in the index ──────────────────────
    if existing_index is not None:
        indexed_ids = set(existing_index["ids"])
        # Also remove any IDs that no longer exist in Drive (deleted photos)
        current_ids = {f["id"] for f in all_files}
        still_valid = [
            (i, eid) for i, eid in enumerate(existing_index["ids"])
            if eid in current_ids
        ]
        if len(still_valid) < len(existing_index["ids"]):
            removed = len(existing_index["ids"]) - len(still_valid)
            st.info(f"Removed {removed} photo(s) from index that were deleted from Drive.")

        kept_idxs = [i for i, _ in still_valid]
        existing_embs  = existing_index["embeddings"][kept_idxs]
        existing_ids   = [existing_index["ids"][i]   for i in kept_idxs]
        existing_names = [existing_index["names"][i] for i in kept_idxs]
        indexed_ids    = set(existing_ids)

        new_files = [f for f in all_files if f["id"] not in indexed_ids]

        if not new_files:
            progress_bar.progress(1.0, text="Already up to date — no new photos found.")
            return existing_index  # nothing to do

        progress_bar.progress(0.0, text=f"Found {len(new_files)} new photo(s) to index…")
    else:
        new_files      = all_files
        existing_embs  = None
        existing_ids   = []
        existing_names = []

    # ── Embed only the new files ──────────────────────────────────────────────
    # Checkpointing: on a large first-time index (thousands of photos going
    # through background removal), a single run can take a long time. If the
    # process gets killed/restarted partway through, we don't want to lose
    # everything — so every CHECKPOINT_EVERY photos we save what we have so
    # far back to Drive. A later "Update (new photos only)" run then only
    # has to redo whatever wasn't checkpointed yet.
    new_embeddings, new_ids, new_names = [], [], []
    for i, f in enumerate(new_files):
        progress_bar.progress(
            (i + 1) / len(new_files),
            text=f"Indexing {i+1}/{len(new_files)}: {f['name']}"
        )
        try:
            raw = fetch_image_bytes(service, f["id"])
            pil = Image.open(io.BytesIO(raw)).convert("RGB")
            isolated = isolate_jewelry(pil)
            with torch.no_grad():
                tensor = preprocess(isolated).unsqueeze(0).to(device)
                feat = model.encode_image(tensor)
                feat = feat / feat.norm(dim=-1, keepdim=True)
            new_embeddings.append(feat.cpu().numpy().astype("float32")[0])
            new_ids.append(f["id"])
            new_names.append(f["name"])
        except Exception as e:
            st.warning(f"Skipped {f['name']}: {e}")

        if new_embeddings and (len(new_embeddings) % CHECKPOINT_EVERY == 0):
            partial = _merge_index(existing_embs, existing_ids, existing_names,
                                    new_embeddings, new_ids, new_names)
            try:
                save_index(service, folder_id, partial)
                st.caption(f"💾 Checkpoint saved — {len(partial['ids'])} photos indexed so far.")
            except Exception as e:
                st.caption(f"⚠️ Checkpoint save failed ({e}) — continuing anyway.")

    if not new_embeddings:
        # All new files errored out — return existing unchanged
        return existing_index

    return _merge_index(existing_embs, existing_ids, existing_names,
                         new_embeddings, new_ids, new_names)


def search(index: dict, query_vec: np.ndarray, top_k: int) -> list[tuple]:
    """Return list of (file_id, name, score) sorted by similarity."""
    sims = index["embeddings"] @ query_vec
    order = np.argsort(-sims)[:top_k]
    return [(index["ids"][i], index["names"][i], float(sims[i])) for i in order]


# ── Website product descriptions (hybrid search) ──────────────────────────────
@st.cache_resource(show_spinner=False)
def load_product_data():
    """Load the bundled Shopify export (title/description/image_url per photo)."""
    path = os.path.join(os.path.dirname(__file__), PRODUCT_DATA_FILENAME)
    with open(path, "r") as f:
        data = json.load(f)
    return data["images"]  # list of {handle, title, image_url, position, description}


def fetch_url_image_bytes(url: str, timeout: int = 20) -> bytes:
    resp = requests.get(url, timeout=timeout)
    resp.raise_for_status()
    return resp.content


def load_website_index(service, folder_id: str):
    """Load the pre-built CLIP+description index for website photos, if it exists."""
    idx_id = _find_file_by_name(service, folder_id, WEBSITE_INDEX_FILENAME)
    if not idx_id:
        return None
    raw = fetch_image_bytes(service, idx_id)
    data = np.load(io.BytesIO(raw), allow_pickle=True)
    return {
        "embeddings":   data["embeddings"],
        "ids":          [str(x) for x in data["urls"]],
        "names":        [str(x) for x in data["names"]],
        "descriptions": [str(x) for x in data["descriptions"]],
    }


def save_website_index(service, folder_id: str, index: dict):
    """Save / overwrite the website CLIP+description index .npz back to Drive."""
    from googleapiclient.http import MediaIoBaseUpload
    buf = io.BytesIO()
    np.savez(buf,
             embeddings=index["embeddings"],
             urls=np.array(index["ids"]),
             names=np.array(index["names"]),
             descriptions=np.array(index["descriptions"]))
    buf.seek(0)
    media = MediaIoBaseUpload(buf, mimetype="application/octet-stream")

    existing_id = _find_file_by_name(service, folder_id, WEBSITE_INDEX_FILENAME)
    if existing_id:
        _execute_with_retry(service.files().update(fileId=existing_id, media_body=media))
    else:
        meta = {"name": WEBSITE_INDEX_FILENAME, "parents": [folder_id]}
        _execute_with_retry(service.files().create(body=meta, media_body=media))


def _merge_website_index(existing_embs, existing_ids, existing_names, existing_descs,
                          new_embeddings, new_ids, new_names, new_descs) -> dict:
    """Stack new website-photo embeddings onto whatever was already indexed."""
    new_emb_arr = np.stack(new_embeddings)
    if existing_embs is not None and len(existing_embs) > 0:
        merged_embs  = np.concatenate([existing_embs, new_emb_arr], axis=0)
        merged_ids   = list(existing_ids)   + list(new_ids)
        merged_names = list(existing_names) + list(new_names)
        merged_descs = list(existing_descs) + list(new_descs)
    else:
        merged_embs  = new_emb_arr
        merged_ids   = list(new_ids)
        merged_names = list(new_names)
        merged_descs = list(new_descs)
    return {"embeddings": merged_embs, "ids": merged_ids,
            "names": merged_names, "descriptions": merged_descs}


def build_website_index(service, folder_id: str, progress_bar, existing_index=None):
    """
    Build or incrementally update the website CLIP+description index.
    Images are downloaded straight from Shopify's CDN (image_url), embedded
    with CLIP, and paired with the product title/description for keyword boosting.
    """
    import torch
    model, preprocess, _, device = load_clip()

    records = load_product_data()

    if existing_index is not None:
        indexed_urls = set(existing_index["ids"])
        new_records = [r for r in records if r["image_url"] not in indexed_urls]
        existing_embs  = existing_index["embeddings"]
        existing_ids   = existing_index["ids"]
        existing_names = existing_index["names"]
        existing_descs = existing_index["descriptions"]

        if not new_records:
            progress_bar.progress(1.0, text="Website index already up to date.")
            return existing_index

        progress_bar.progress(0.0, text=f"Found {len(new_records)} new website photo(s)…")
    else:
        new_records    = records
        existing_embs  = None
        existing_ids, existing_names, existing_descs = [], [], []

    new_embeddings, new_ids, new_names, new_descs = [], [], [], []
    for i, r in enumerate(new_records):
        progress_bar.progress(
            (i + 1) / len(new_records),
            text=f"Indexing website photo {i+1}/{len(new_records)}: {r['title'][:40]}"
        )
        try:
            raw = fetch_url_image_bytes(r["image_url"])
            pil = Image.open(io.BytesIO(raw)).convert("RGB")
            isolated = isolate_jewelry(pil)
            with torch.no_grad():
                tensor = preprocess(isolated).unsqueeze(0).to(device)
                feat = model.encode_image(tensor)
                feat = feat / feat.norm(dim=-1, keepdim=True)
            new_embeddings.append(feat.cpu().numpy().astype("float32")[0])
            new_ids.append(r["image_url"])
            new_names.append(r["title"])
            new_descs.append(r["description"])
        except Exception as e:
            st.warning(f"Skipped website photo ({r['title'][:30]}): {e}")

        if new_embeddings and (len(new_embeddings) % CHECKPOINT_EVERY == 0):
            partial = _merge_website_index(existing_embs, existing_ids, existing_names, existing_descs,
                                            new_embeddings, new_ids, new_names, new_descs)
            try:
                save_website_index(service, folder_id, partial)
                st.caption(f"💾 Checkpoint saved — {len(partial['ids'])} website photos indexed so far.")
            except Exception as e:
                st.caption(f"⚠️ Checkpoint save failed ({e}) — continuing anyway.")

    if not new_embeddings:
        return existing_index

    return _merge_website_index(existing_embs, existing_ids, existing_names, existing_descs,
                                 new_embeddings, new_ids, new_names, new_descs)


def _keyword_overlap(query_text: str, description: str) -> float:
    """Fraction of query words that appear literally in the description."""
    q_words = set(re.findall(r"[a-z0-9]+", query_text.lower()))
    if not q_words:
        return 0.0
    d_words = set(re.findall(r"[a-z0-9]+", description.lower()))
    return len(q_words & d_words) / len(q_words)


def hybrid_search(drive_index, website_index, query_vec: np.ndarray,
                   query_text: str, top_k: int) -> list[dict]:
    """
    Merge Drive-only results (pure CLIP similarity) with website results
    (CLIP similarity boosted by literal keyword overlap against the human-
    written description) into one ranked list.
    """
    results = []

    if drive_index is not None and len(drive_index["ids"]) > 0:
        sims = drive_index["embeddings"] @ query_vec
        for i in range(len(drive_index["ids"])):
            results.append({
                "source": "drive",
                "id":     drive_index["ids"][i],
                "name":   drive_index["names"][i],
                "score":  float(sims[i]),
            })

    if website_index is not None and len(website_index["ids"]) > 0:
        sims = website_index["embeddings"] @ query_vec
        for i in range(len(website_index["ids"])):
            clip_score = float(sims[i])
            kw = _keyword_overlap(query_text, website_index["descriptions"][i]) if query_text else 0.0
            # Multiplicative boost: exact material/gem/style matches in the
            # description float clearly relevant pieces to the top without
            # letting keyword-only matches drown out visual similarity entirely.
            final_score = clip_score * (1 + 0.6 * kw)
            results.append({
                "source": "web",
                "id":     website_index["ids"][i],
                "name":   website_index["names"][i],
                "score":  final_score,
            })

    results.sort(key=lambda r: -r["score"])
    return results[:top_k]


